import requests, json, sys, os, urllib.request
from datetime import datetime

sys.stdout.reconfigure(encoding='utf-8')
sys.stderr.reconfigure(encoding='utf-8')

UPLOAD_DIR = r'C:\Users\linkang\.openclaw\workspace\uploads'
os.makedirs(UPLOAD_DIR, exist_ok=True)

WEBHOOK_FILE = r'C:\Users\linkang\.openclaw\workspace\MCP_CONFIG.md'
FEISHU_WEBHOOK = None

def get_webhook():
    global FEISHU_WEBHOOK
    if FEISHU_WEBHOOK:
        return FEISHU_WEBHOOK
    try:
        import re
        content = open(WEBHOOK_FILE, 'r', encoding='utf-8').read()
        m = re.search(r'https://open[^\s"]+feishu[^\s"]+', content)
        if m:
            FEISHU_WEBHOOK = m.group()
    except:
        pass
    return FEISHU_WEBHOOK

def connect_sse():
    """Connect to MediaCrawler MCP SSE endpoint and get session_id"""
    r = requests.get('http://127.0.0.1:18080/sse', stream=True, timeout=10)
    endpoint = None
    for line in r.iter_lines():
        line = line.decode()
        if line.startswith('data:'):
            data = line[5:].strip()
            if 'session_id' in data:
                import re
                m = re.search(r'session_id=([^&]+)', data)
                if m:
                    endpoint = f'/messages/?session_id={m.group(1)}'
                    break
    r.close()
    return endpoint

def call_mcp(endpoint, tool_name, arguments, timeout=120):
    resp = requests.post(f'http://127.0.0.1:18080{endpoint}', json={
        'jsonrpc': '2.0', 'id': 1, 'method': 'tools/call',
        'params': {'name': tool_name, 'arguments': arguments}
    }, timeout=timeout)
    return json.loads(resp.json()['result']['content'][0]['text'])

def download(url, path):
    if not url:
        return False
    try:
        r = requests.get(url, timeout=15)
        if r.status_code == 200:
            with open(path, 'wb') as f:
                f.write(r.content)
            return True
    except:
        pass
    return False

def send_feishu_text(text):
    webhook = get_webhook()
    if not webhook:
        print('未找到飞书 webhook，无法推送', file=sys.stderr)
        return False
    try:
        payload = json.dumps({'msg_type': 'text', 'content': {'text': text}}).encode('utf-8')
        req = urllib.request.Request(webhook, data=payload,
                                     headers={'Content-Type': 'application/json'})
        urllib.request.urlopen(req, timeout=10)
        return True
    except Exception as e:
        print(f'飞书推送失败: {e}', file=sys.stderr)
        return False

def send_feishu_image(text, img_path):
    webhook = get_webhook()
    if not webhook:
        print('未找到飞书 webhook，无法推送', file=sys.stderr)
        return False
    try:
        import base64
        with open(img_path, 'rb') as f:
            img_data = base64.b64encode(f.read()).decode()
        payload = {
            'msg_type': 'post',
            'content': {
                'post': {
                    'zh_cn': {
                        'title': '小红书旅游热度',
                        'content': [[
                            {'tag': 'text', 'text': text},
                            {'tag': 'at', 'user_id': 'all'}
                        ]]
                    }
                }
            }
        }
        # Try image message
        payload2 = {
            'msg_type': 'image',
            'content': {'image_key': img_data}
        }
        # Actually, feishu webhook doesn't support base64 directly for image
        # Use post with image
        payload3 = {
            'msg_type': 'post',
            'content': {
                'post': {
                    'zh_cn': {
                        'title': '📌 小红书旅游热度',
                        'content': [[{'tag': 'text', 'text': text}]]
                    }
                }
            }
        }
        data = json.dumps(payload3).encode('utf-8')
        req = urllib.request.Request(webhook, data=data,
                                     headers={'Content-Type': 'application/json'})
        urllib.request.urlopen(req, timeout=10)
        return True
    except Exception as e:
        print(f'飞书推送失败: {e}', file=sys.stderr)
        return False

def main():
    print('=== 小红书旅游推送开始 ===')

    endpoint = connect_sse()
    if not endpoint:
        print('无法连接到 MediaCrawler MCP', file=sys.stderr)
        return
    print(f'已连接 MCP，endpoint: {endpoint}')

    kws = ['旅游', '旅行', '出游', '攻略']
    all_results = []
    seen_ids = set()

    for kw in kws:
        print(f'搜索关键词: {kw}')
        try:
            raw = call_mcp(endpoint, 'crawl_search', {
                'platform': 'xhs',
                'store_type': 'json',
                'keywords': kw
            }, timeout=120)
            print(f'  原始返回: {str(raw)[:200]}')
            items = raw if isinstance(raw, list) else []
            for item in items:
                note_id = item.get('note_id', '') or item.get('id', '')
                if not note_id or note_id in seen_ids:
                    continue
                seen_ids.add(note_id)

                title = item.get('title', '') or item.get('display_title', '')
                liked = item.get('liked_count', item.get('like_count', 0))
                user = item.get('nickname', item.get('user', {}).get('nickname', ''))
                # cover
                cover = item.get('cover', {}) or {}
                if isinstance(cover, dict):
                    cover_url = cover.get('url_default', cover.get('url', ''))
                elif isinstance(cover, str):
                    cover_url = cover
                else:
                    cover_url = ''

                if not title:
                    continue

                all_results.append({
                    'id': note_id,
                    'title': title,
                    'cover_url': cover_url,
                    'like': liked,
                    'user': user
                })
        except Exception as e:
            print(f'  搜索 {kw} 出错: {e}', file=sys.stderr)

        if len(all_results) >= 15:
            break

    all_results.sort(key=lambda x: int(x.get('like', 0) or 0), reverse=True)
    feeds = all_results[:5]
    print(f'获取到 {len(feeds)} 条内容')

    today = datetime.now().strftime('%Y-%m-%d')

    push_texts = []
    for i, f in enumerate(feeds, 1):
        title = f['title']
        like = f['like']
        user = f['user']
        cover_url = f['cover_url']

        text = f'📌 {title}\n👍 {like} | @{user}'
        push_texts.append((text, cover_url, i))
        print(f'{i}. {title} | 👍{like} | @{user} | {cover_url}')

    # 下载封面
    for text, cover_url, i in push_texts:
        if cover_url:
            img_path = os.path.join(UPLOAD_DIR, f'push_{i}.jpg')
            if download(cover_url, img_path):
                print(f'  封面已下载: {img_path}')

    # 发飞书 - 每条发一条消息
    header = f'📊 小红书旅游热度Top5（{today}）\n'
    for text, _, i in push_texts:
        send_feishu_text(header + text)
        print(f'  已推送: {text[:30]}...')

    # 保存数据
    with open(os.path.join(UPLOAD_DIR, 'push_data.json'), 'w', encoding='utf-8') as fp:
        json.dump({'feeds': feeds}, fp, ensure_ascii=False, indent=2)

    print('=== 完成 ===')

if __name__ == '__main__':
    main()

